new file mode 100644
index 00000000000..0894cb2fa42
--- /dev/null
+++ b/docs/changelog/114715.yaml
@@ -0,0 +1,5 @@
+pr: 114715
+summary: Ignore unrecognized openai sse fields
+area: Machine Learning
+type: bug
+issues: []
